```typescript
// 添加 Dashboard 集成
import { getDashboardServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices: any = null;

  async initializeDashboard() {
    try {
      this.dashboardServices = await getDashboardServices();
    } catch (e) {
      console.log('Dashboard not available, running standalone');
    }
  }

  // 迭代开始时通知
  async notifyIterationStart(iteration: number, task: string) {
    if (!this.dashboardServices) return;

    await this.dashboardServices.iterationService.create({
      iterationNumber: iteration,
      status: 'running',
      requirement: task,
      startedAt: new Date()
    });

    this.dashboardServices.realtimeService.broadcast('iteration.started', {
      iteration,
      task,
      timestamp: new Date()
    });
  }

  // Agent 状态更新
  async notifyAgentStatus(agentName: string, status: string, progress: number) {
    if (!this.dashboardServices) return;

    this.dashboardServices.realtimeService.broadcast('agent.status_changed', {
      agentName,
      status,
      progress,
      timestamp: new Date()
    });
  }

  // 迭代完成
  async notifyIterationComplete(result: IterationResult) {
    if (!this.dashboardServices) return;

    await this.dashboardServices.iterationService.updateStatus(
      result.iteration,
      result.status
    );

    this.dashboardServices.realtimeService.broadcast('iteration.completed', result);
  }
}
```

