// 补充完整的路由实现
export async function registerRoutes(fastify, services) {
  const { iterationService, agentService, projectService, systemService } = services;

  // ========== 迭代相关 API ==========

  // 获取迭代列表（分页）
  fastify.get('/api/iterations', async (request, reply) => {
    const { page = 1, limit = 20, status } = request.query as any;
    const result = await iterationService.list({
      page: Number(page),
      limit: Number(limit),
      status
    });
    return result;
  });

  // 获取迭代详情
  fastify.get('/api/iterations/:id', async (request, reply) => {
    const { id } = request.params as any;
    const iteration = await iterationService.getById(Number(id));
    if (!iteration) {
      return reply.status(404).send({ error: 'Iteration not found' });
    }
    return iteration;
  });

  // 获取当前运行的迭代
  fastify.get('/api/iterations/current', async (request, reply) => {
    const current = await iterationService.getCurrent();
    return current || { message: 'No running iteration' };
  });

  // ========== Agent 相关 API ==========

  // 获取所有 Agent 状态
  fastify.get('/api/agents', async (request, reply) => {
    const agents = await agentService.getAllStatus();
    return agents;
  });

  // 获取特定 Agent 详情
  fastify.get('/api/agents/:name', async (request, reply) => {
    const { name } = request.params as any;
    const agent = await agentService.getByName(name);
    return agent;
  });

  // ========== 系统相关 API ==========

  // 系统概览
  fastify.get('/api/system/overview', async (request, reply) => {
    const overview = await systemService.getOverview();
    return overview;
  });

  // 系统指标
  fastify.get('/api/system/metrics', async (request, reply) => {
    const metrics = await systemService.getMetrics();
    return metrics;
  });

  // 健康检查
  fastify.get('/api/system/health', async (request, reply) => {
    return { 
      status: 'healthy',
      timestamp: new Date(),
      uptime: process.uptime()
    };
  });
}
```

